    csv_filename: `cmdb_movimientos_inventario_${generatedAtFile}.csv`,
  },
  binary: {
    csv: {
      data: Buffer.from(csvContent, 'utf8').toString('base64'),
      mimeType: 'text/csv',
      fileName: `cmdb_movimientos_inventario_${generatedAtFile}.csv`,
    }
  }
}];

